const CACHE_NAME="statsync-cache-v10",ASSETS_TO_CACHE=["./taskpane.html","./taskpane.js","./dialog.html","./dialog.js","https://appsforoffice.microsoft.com/lib/1.1/hosted/office.js"];self.addEventListener("install",e=>{self.skipWaiting(),e.waitUntil(caches.open(CACHE_NAME).then(e=>e.addAll(ASSETS_TO_CACHE)))}),self.addEventListener("activate",e=>{e.waitUntil(Promise.all([self.clients.claim(),caches.keys().then(e=>Promise.all(e.filter(e=>e!==CACHE_NAME).map(e=>caches.delete(e))))]))}),self.addEventListener("fetch",e=>{e.respondWith(caches.match(e.request).then(t=>t||fetch(e.request)))});